sql:
SELECT COUNT(view_id) AS view_count 
FROM movie_views 
WHERE movie_id = 1;

external_knowledge:
- "blossomed in the garden of reviews and ratings" refers to movies that have received multiple ratings and at least one review;
- "blooming with more than one rating" means the movie has more than one rating;
- "at least one review" means the movie has at least one review.

sql:
SELECT AVG(r.rating) AS average_rating
FROM ratings AS r
JOIN reviews AS rv ON r.movie_id = rv.movie_id;

external_knowledge:
